var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"서윤! 서윤!! 괜찮아?!","JPN":"シズカ！　シズカ！！　大丈夫！？","ENG":"Seo Yoon! Seo Yoon! You okay?","TWN":"徐芸！徐芸！！你還好嗎？"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"제길, 분명 뭔가 폭발하는 소리가 들렸는데…….","JPN":"くそっ、確かに何かが爆発する音が聞こえたのに……","ENG":"Damn it, I thought I just heard an explosion…","TWN":"可惡！我明明有聽到爆炸聲……"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……아냐. 침착해, 유미나.","JPN":"……違う。落ち着いて、ヤナギ・ミナ。","ENG":"Wait… I should stay calm.","TWN":"……不，劉米娜你冷靜點！"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"서윤이라면 상대가 누구든 쉽게 당해 주진 않을 거야.","JPN":"シズカなら相手が誰であれ、簡単にはやられない。","ENG":"She wouldn't go down so easily.","TWN":"她可是徐芸，她是不會輕易落入敵人手中的！"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배를 구하러 가야 해. 그걸 위해 다들 위험을 감수해 줬으니까.","JPN":"先輩を助けに行くべきだ。そのためにみんなが危険を冒してくれたんだ。","ENG":"I have to save Shiyoon. That's why everyone's risking their lives so far.","TWN":"我要去找前輩！她們冒這麼多的危險就是為了要救出前輩！"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저건……?","JPN":"あれは……？","ENG":"What the…","TWN":"那是……？"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"몸이…… 저릿저릿한데. 다이브 훈련에서 만났던 그 이상한 녀석이랑 같아.","JPN":"体が……しびれてくる。ダイブ訓練で会ったあの変なやつと同じだ。","ENG":"It's sending chills down my spine… It's like that weird one from the dive training.","TWN":"身體……麻麻的，好像是躍入訓練時遇到的那個怪傢伙。"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 저 녀석도 4종 침식체인가?","JPN":"まさかあいつも第4種侵食体？","ENG":"Could that be a Category 4 C.O. as well?","TWN":"難道那傢伙也是4類侵蝕體？"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우회할 방법은…… 없나.","JPN":"迂回する方法は……ないか。","ENG":"Maybe there's a way around it… or not.","TWN":"避不掉……的話，"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그렇다면, 정면으로 돌파할 수밖에!","JPN":"なら正面から突破してやる！","ENG":"I guess I'll just have to face it head-on then!","TWN":"那就正面迎戰吧！！"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ff3636>……좋은 각오다. 저주받은 늑대.</color>","JPN":"<color=#ff3636>……いい覚悟だ。呪われた狼。</color>","ENG":"<color=#ff3636>…I commend thy resolve. Cursed Wolf.</color>","TWN":"<color=#ff3636>……非常好，受到詛咒的狼。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ff3636>자고로 공연의 시작은 유혈로 장식해야 하는 법.</color>","JPN":"<color=#ff3636>やはり公演の序幕は流血で飾らねば。</color>","ENG":"<color=#ff3636>Every good show starts with a little bloodshed, after all.</color>","TWN":"<color=#ff3636>戲裡就是要有打打殺殺才好看嘛！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ff3636>하찮은 짐승에 불과하지만 지금의 네 성취를 가늠하기에는 적당하겠군.</color>","JPN":"<color=#ff3636>下等な獣に過ぎないが、貴様の成就をはかるには適しているだろうな。</color>","ENG":"<color=#ff3636>This petty beast should suffice to gauge how far you've come.</color>","TWN":"<color=#ff3636>雖然就像是一群動物在打架，但我也不好挑剔什麼。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐, 뭐야? 방금 누구야?!","JPN":"な、なに？　今のは誰！？","ENG":"W-what the? Who was that just now?","TWN":"說…在說什麼？是誰？！"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아무도 없잖아, 환청인가……?","JPN":"誰もいない、幻聴……？","ENG":"There's nobody here…? Am I hearing things?","TWN":"沒人？幻聽嗎……？"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭!!","JPN":"くっ！！","ENG":"Ngh!","TWN":"嚇！！"},"stage":{"bg":"CASTLE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};